import redis

def run_lua_script(host='localhost', port=6379, db=0):
    """
    Connects to Redis, accepts a Lua script and parameters from user input,
    and executes the script using redis.eval().
    """
    try:
        r = redis.Redis(host=host, port=port, db=db, decode_responses=True)
        r.ping()
        print(f"Connected to Redis at {host}:{port}/{db}")
    except redis.exceptions.ConnectionError as e:
        print(f"Could not connect to Redis: {e}")
        return

    print("\nEnter your Lua script (type 'END' on a new line to finish):")
    lua_script_lines = []
    while True:
        line = input()
        if line == 'END':
            break
        lua_script_lines.append(line)
    lua_script = "\n".join(lua_script_lines)

    print("\nEnter KEYS (comma-separated, e.g., key1,key2):")
    keys_input = input().strip()
    keys = [k.strip() for k in keys_input.split(',') if k.strip()]

    print("\nEnter ARGV (comma-separated, e.g., arg1,arg2):")
    argv_input = input().strip()
    argv = [a.strip() for a in argv_input.split(',') if a.strip()]

    num_keys = len(keys)

    print(f"\nExecuting Lua script with {num_keys} keys and {len(argv)} arguments:")
    print("--- SCRIPT ---")
    print(lua_script)
    print("--- KEYS ---")
    print(keys)
    print("--- ARGV ---")
    print(argv)
    print("--- RESULT ---")

    try:
        result = r.eval(lua_script, num_keys, *keys, *argv)
        print(result)
    except redis.exceptions.RedisError as e:
        print(f"Error executing Lua script: {e}")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")

if __name__ == "__main__":
    run_lua_script()